const questionnaireHtml = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>שאלון אפיון למערכת הזמנות</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f6f7f8;\n      --panel: #ffffff;\n      --ink: #17202a;\n      --muted: #64707d;\n      --line: #dfe5eb;\n      --accent: #1c7c54;\n      --accent-dark: #145c3e;\n      --warn: #8a5a00;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.55;\n    }\n\n    main {\n      width: min(920px, calc(100% - 28px));\n      margin: 0 auto;\n      padding: 28px 0 42px;\n    }\n\n    header {\n      margin-bottom: 22px;\n    }\n\n    h1 {\n      margin: 0 0 8px;\n      font-size: 30px;\n      line-height: 1.2;\n    }\n\n    .intro {\n      margin: 0;\n      color: var(--muted);\n      font-size: 16px;\n    }\n\n    form {\n      display: grid;\n      gap: 14px;\n    }\n\n    section {\n      background: var(--panel);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      padding: 18px;\n    }\n\n    h2 {\n      margin: 0 0 14px;\n      font-size: 20px;\n    }\n\n    label {\n      display: block;\n      font-weight: 700;\n      margin-bottom: 7px;\n    }\n\n    .field {\n      margin-bottom: 16px;\n    }\n\n    .field:last-child {\n      margin-bottom: 0;\n    }\n\n    input,\n    textarea,\n    select {\n      width: 100%;\n      border: 1px solid #cfd8e3;\n      border-radius: 7px;\n      padding: 11px 12px;\n      font: inherit;\n      color: var(--ink);\n      background: #fff;\n    }\n\n    textarea {\n      min-height: 92px;\n      resize: vertical;\n    }\n\n    .choices {\n      display: grid;\n      gap: 8px;\n    }\n\n    .choice {\n      display: flex;\n      align-items: flex-start;\n      gap: 9px;\n      padding: 9px 10px;\n      border: 1px solid var(--line);\n      border-radius: 7px;\n      background: #fbfcfd;\n      font-weight: 400;\n    }\n\n    .choice input {\n      width: auto;\n      margin-top: 4px;\n    }\n\n    .hint {\n      margin-top: 6px;\n      color: var(--muted);\n      font-size: 13px;\n    }\n\n    .actions {\n      position: sticky;\n      bottom: 0;\n      display: flex;\n      flex-wrap: wrap;\n      gap: 10px;\n      padding: 12px 0 0;\n      background: linear-gradient(to top, var(--bg) 70%, rgba(246, 247, 248, 0));\n    }\n\n    button {\n      border: 0;\n      border-radius: 7px;\n      padding: 11px 16px;\n      font: inherit;\n      font-weight: 700;\n      cursor: pointer;\n    }\n\n    .primary {\n      background: var(--accent);\n      color: #fff;\n    }\n\n    .primary:hover {\n      background: var(--accent-dark);\n    }\n\n    .secondary {\n      background: #e7ecef;\n      color: var(--ink);\n    }\n\n    .notice {\n      display: none;\n      margin-top: 10px;\n      color: var(--accent-dark);\n      font-weight: 700;\n    }\n\n    .warning {\n      color: var(--warn);\n    }\n\n    @media (max-width: 640px) {\n      main {\n        width: min(100% - 18px, 920px);\n        padding-top: 18px;\n      }\n\n      h1 {\n        font-size: 24px;\n      }\n\n      section {\n        padding: 14px;\n      }\n\n      .actions {\n        display: grid;\n      }\n    }\n  </style>\n</head>\n<body>\n  <main>\n    <header>\n      <h1>שאלון קצר לאפיון מערכת הזמנות</h1>\n      <p class=\"intro\">המטרה היא להבין איך העסק עובד היום, כדי לבנות מערכת CRM והזמנות שמתאימה בפועל לעבודה היומיומית.</p>\n    </header>\n\n    <form id=\"questionnaire\">\n      <section>\n        <h2>פרטי העסק</h2>\n        <div class=\"field\">\n          <label for=\"businessName\">שם העסק</label>\n          <input id=\"businessName\" name=\"שם העסק\" autocomplete=\"organization\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactName\">שם איש קשר</label>\n          <input id=\"contactName\" name=\"שם איש קשר\" autocomplete=\"name\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactPhone\">טלפון</label>\n          <input id=\"contactPhone\" name=\"טלפון\" autocomplete=\"tel\">\n        </div>\n      </section>\n\n      <section>\n        <h2>היקף פעילות</h2>\n        <div class=\"field\">\n          <label for=\"customerCount\">כמה לקוחות קיימים יש בערך?</label>\n          <input id=\"customerCount\" name=\"כמות לקוחות קיימים\" placeholder=\"לדוגמה: 200 / 800 / לא יודע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"ordersCount\">כמה הזמנות יש בערך ביום או בשבוע?</label>\n          <input id=\"ordersCount\" name=\"כמות הזמנות\" placeholder=\"לדוגמה: 10 ביום / 60 בשבוע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"productCount\">כמה מוצרים / שקים שונים יש בערך בקטלוג?</label>\n          <input id=\"productCount\" name=\"כמות מוצרים\" placeholder=\"לדוגמה: 40 / 150 / לא יודע\">\n        </div>\n      </section>\n\n      <section>\n        <h2>לקוחות והזמנות</h2>\n        <div class=\"field\">\n          <label>האם לקוח יכול להזמין כמה מוצרים באותה הזמנה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"כן\"> כן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא, בדרך כלל מוצר אחד\"> לא, בדרך כלל מוצר אחד</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"manualOrders\">באילו מקרים בעל העסק יפתח הזמנה ידנית?</label>\n          <textarea id=\"manualOrders\" name=\"מקרים להזמנה ידנית\" placeholder=\"לדוגמה: לקוחות מבוגרים, הזמנות טלפוניות, לקוח שלא מסתדר עם האתר\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"specialCustomers\">האם יש לקוחות עם תנאים מיוחדים?</label>\n          <textarea id=\"specialCustomers\" name=\"לקוחות עם תנאים מיוחדים\" placeholder=\"לדוגמה: מחיר קבוע, הנחה, תשלום אחרי אספקה, חוב פתוח\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>קטלוג ומחירים</h2>\n        <div class=\"field\">\n          <label>איך נכון להציג מוצרים?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"מותג/סדרה ואז בחירת סוג, טעם ומשקל\"> מותג/סדרה ואז בחירת סוג, טעם ומשקל</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"רשימת שקים נפרדים\"> רשימת שקים נפרדים</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"לא משנה לי\"> לא משנה לי</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"priceRules\">איך מחירים מיוחדים והנחות עובדים היום?</label>\n          <textarea id=\"priceRules\" name=\"כללי מחירים והנחות\" placeholder=\"לדוגמה: יש לקוחות עם מחיר קבוע, מבצעים לפי מוצר, הנחות לפי לקוח\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"substitutes\">האם יש מוצרים תחליפיים כשמוצר חסר?</label>\n          <textarea id=\"substitutes\" name=\"מוצרים תחליפיים\" placeholder=\"לדוגמה: אם אין עוף מציעים כבש, אם אין 12 קג מציעים 2 של 6 קג\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>משלוחים</h2>\n        <div class=\"field\">\n          <label>איך החלוקה מתבצעת היום?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי ימים קבועים\"> לפי ימים קבועים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי אזורים\"> לפי אזורים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי עיר/שכונה\"> לפי עיר/שכונה</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"ידנית לפי מה שנוח\"> ידנית לפי מה שנוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryDays\">האם יש ימי חלוקה קבועים?</label>\n          <input id=\"deliveryDays\" name=\"ימי חלוקה קבועים\" placeholder=\"לדוגמה: ראשון ושלישי באזור המרכז\">\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryAreas\">אילו אזורים / ערים העסק משרת?</label>\n          <textarea id=\"deliveryAreas\" name=\"אזורי שירות\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label>האם לקוח צריך לבחור מועד אספקה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"כן, הלקוח בוחר מועד זמין\"> כן, הלקוח בוחר מועד זמין</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא, העסק קובע ומעדכן\"> לא, העסק קובע ומעדכן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n          <div class=\"hint\">כרגע ידוע שצריך התראה של יומיים מראש.</div>\n        </div>\n      </section>\n\n      <section>\n        <h2>תשלומים וחשבוניות</h2>\n        <div class=\"field\">\n          <label>אילו אמצעי תשלום קיימים בפועל?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"קישור תשלום משולם\"> קישור תשלום משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"bit דרך משולם\"> bit דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"Google Pay דרך משולם\"> Google Pay דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"מזומן לשליח\"> מזומן לשליח</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"העברה בנקאית\"> העברה בנקאית</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"cashInvoice\">איך מפיקים חשבונית / קבלה על מזומן לשליח?</label>\n          <textarea id=\"cashInvoice\" name=\"חשבונית על מזומן לשליח\" placeholder=\"לדוגמה: דרך משולם ידנית, אחרי שהשליח חוזר, דרך מערכת אחרת\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"failedPayments\">מה עושים היום עם לקוח שלא שילם?</label>\n          <textarea id=\"failedPayments\" name=\"טיפול באי תשלום\" placeholder=\"לדוגמה: מתקשרים אליו, לא מוציאים משלוח, מסמנים חוב\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>עבודה יומיומית</h2>\n        <div class=\"field\">\n          <label>איפה בעל העסק יעבוד עם המערכת בעיקר?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"טלפון\"> טלפון</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"מחשב\"> מחשב</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"גם וגם\"> גם וגם</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"currentPain\">מה הכי מפריע היום בהתנהלות הקיימת?</label>\n          <textarea id=\"currentPain\" name=\"כאבים עיקריים היום\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"success\">מה ייחשב הצלחה מבחינתך אחרי חודש שימוש?</label>\n          <textarea id=\"success\" name=\"מדד הצלחה אחרי חודש\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>הערות נוספות</h2>\n        <div class=\"field\">\n          <label for=\"notes\">כל דבר נוסף שחשוב שנדע</label>\n          <textarea id=\"notes\" name=\"הערות נוספות\"></textarea>\n        </div>\n      </section>\n\n      <div class=\"actions\">\n        <button class=\"primary\" type=\"button\" id=\"copyAnswers\">העתקת התשובות</button>\n        <button class=\"secondary\" type=\"button\" id=\"downloadAnswers\">הורדת קובץ תשובות</button>\n        <button class=\"secondary\" type=\"reset\">ניקוי הטופס</button>\n      </div>\n      <div class=\"notice\" id=\"notice\">התשובות הועתקו. אפשר להדביק אותן בוואטסאפ או במייל.</div>\n      <p class=\"hint warning\">הטופס לא שולח מידע לשרת. אחרי המילוי יש ללחוץ על העתקת התשובות או הורדת קובץ.</p>\n    </form>\n  </main>\n\n  <script>\n    const form = document.getElementById('questionnaire');\n    const notice = document.getElementById('notice');\n\n    function collectAnswers() {\n      const data = new FormData(form);\n      const grouped = {};\n\n      for (const [key, value] of data.entries()) {\n        if (!value || !String(value).trim()) continue;\n        if (!grouped[key]) grouped[key] = [];\n        grouped[key].push(String(value).trim());\n      }\n\n      const lines = ['שאלון אפיון מערכת הזמנות', ''];\n      for (const [key, values] of Object.entries(grouped)) {\n        lines.push(`${key}: ${values.join(', ')}`);\n      }\n\n      if (lines.length === 2) {\n        lines.push('לא מולאו תשובות עדיין.');\n      }\n\n      return lines.join('\\n');\n    }\n\n    document.getElementById('copyAnswers').addEventListener('click', async () => {\n      const text = collectAnswers();\n\n      try {\n        await navigator.clipboard.writeText(text);\n        notice.style.display = 'block';\n      } catch (error) {\n        const area = document.createElement('textarea');\n        area.value = text;\n        document.body.appendChild(area);\n        area.select();\n        document.execCommand('copy');\n        area.remove();\n        notice.style.display = 'block';\n      }\n    });\n\n    document.getElementById('downloadAnswers').addEventListener('click', () => {\n      const text = collectAnswers();\n      const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = 'drive-dog-questionnaire-answers.txt';\n      document.body.appendChild(link);\n      link.click();\n      link.remove();\n      URL.revokeObjectURL(url);\n    });\n  </script>\n</body>\n</html>\n";
const proposalHtml = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>הצעת MVP - Drive Dog</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f4f6f5;\n      --paper: #ffffff;\n      --ink: #14211c;\n      --muted: #5f6e68;\n      --line: #dce4df;\n      --green: #176b4d;\n      --green-2: #0f4935;\n      --gold: #c18a28;\n      --blue: #24506d;\n      --soft: #eef4f1;\n      --warn: #fff5df;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.6;\n    }\n\n    .hero {\n      min-height: 74vh;\n      display: flex;\n      align-items: center;\n      padding: 48px 24px 92px;\n      color: #fff;\n      background:\n        linear-gradient(90deg, rgba(15, 73, 53, .96), rgba(23, 107, 77, .84)),\n        url(\"https://images.unsplash.com/photo-1589924691995-400dc9ecc119?auto=format&fit=crop&w=1800&q=80\");\n      background-size: cover;\n      background-position: center;\n    }\n\n    .hero-inner,\n    .wrap {\n      width: min(1080px, calc(100% - 32px));\n      margin: 0 auto;\n    }\n\n    .eyebrow {\n      display: inline-flex;\n      align-items: center;\n      gap: 9px;\n      padding: 8px 12px;\n      border: 1px solid rgba(255, 255, 255, .35);\n      border-radius: 999px;\n      background: rgba(255, 255, 255, .12);\n      font-weight: 700;\n    }\n\n    h1,\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h1 {\n      max-width: 780px;\n      margin: 22px 0 16px;\n      font-size: 58px;\n      line-height: 1.08;\n      letter-spacing: 0;\n    }\n\n    .hero p {\n      max-width: 760px;\n      margin-bottom: 0;\n      color: rgba(255, 255, 255, .88);\n      font-size: 22px;\n    }\n\n    .proposal-meta {\n      display: grid;\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n      gap: 10px;\n      max-width: 820px;\n      margin-top: 28px;\n    }\n\n    .meta-item {\n      padding: 12px 14px;\n      border: 1px solid rgba(255, 255, 255, .28);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, .12);\n    }\n\n    .meta-item span {\n      display: block;\n      color: rgba(255, 255, 255, .72);\n      font-size: 13px;\n    }\n\n    .meta-item strong {\n      display: block;\n      margin-top: 3px;\n      color: #fff;\n    }\n\n    .summary-strip {\n      margin-top: -52px;\n      position: relative;\n      z-index: 2;\n    }\n\n    .summary-grid {\n      display: grid;\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      gap: 12px;\n    }\n\n    .summary-item,\n    .panel,\n    .scope-item,\n    .phase,\n    .risk {\n      background: var(--paper);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      box-shadow: 0 16px 42px rgba(34, 48, 42, .07);\n    }\n\n    .summary-item {\n      min-height: 118px;\n      padding: 18px;\n    }\n\n    .summary-item strong {\n      display: block;\n      margin-bottom: 8px;\n      color: var(--green-2);\n      font-size: 26px;\n      line-height: 1.2;\n    }\n\n    .summary-item span,\n    p,\n    li {\n      color: var(--muted);\n    }\n\n    section {\n      padding: 58px 0;\n    }\n\n    .section-head {\n      margin-bottom: 20px;\n    }\n\n    .section-head span {\n      color: var(--gold);\n      font-weight: 800;\n    }\n\n    h2 {\n      margin-bottom: 8px;\n      font-size: 34px;\n      line-height: 1.2;\n      letter-spacing: 0;\n    }\n\n    h3 {\n      margin-bottom: 10px;\n      font-size: 21px;\n      line-height: 1.25;\n    }\n\n    .grid-2,\n    .grid-3 {\n      display: grid;\n      gap: 14px;\n    }\n\n    .grid-2 {\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n    }\n\n    .grid-3 {\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n    }\n\n    .panel,\n    .scope-item,\n    .phase,\n    .risk {\n      padding: 20px;\n    }\n\n    .panel.accent {\n      background: var(--soft);\n      border-color: #c9d9d1;\n    }\n\n    ul,\n    ol {\n      margin: 0;\n      padding: 0 20px 0 0;\n    }\n\n    li {\n      margin: 8px 0;\n    }\n\n    .tag {\n      display: inline-flex;\n      margin: 0 0 12px;\n      padding: 5px 9px;\n      border-radius: 999px;\n      background: #e7f0eb;\n      color: var(--green-2);\n      font-size: 13px;\n      font-weight: 700;\n    }\n\n    .scope-list {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 12px;\n    }\n\n    .scope-item {\n      min-height: 132px;\n    }\n\n    .scope-item strong {\n      display: block;\n      margin-bottom: 7px;\n      font-size: 18px;\n    }\n\n    .timeline {\n      display: grid;\n      gap: 12px;\n      counter-reset: phase;\n    }\n\n    .phase {\n      display: grid;\n      grid-template-columns: 58px 1fr;\n      gap: 14px;\n      align-items: start;\n    }\n\n    .phase::before {\n      counter-increment: phase;\n      content: counter(phase);\n      display: grid;\n      place-items: center;\n      width: 42px;\n      height: 42px;\n      border-radius: 999px;\n      background: var(--green);\n      color: #fff;\n      font-weight: 800;\n    }\n\n    .risk {\n      background: var(--warn);\n      border-color: #ecd7a7;\n    }\n\n    .placeholder {\n      display: grid;\n      gap: 10px;\n    }\n\n    .placeholder-row {\n      display: grid;\n      grid-template-columns: 180px 1fr;\n      gap: 12px;\n      align-items: center;\n      padding: 12px 0;\n      border-bottom: 1px solid var(--line);\n    }\n\n    .placeholder-row:last-child {\n      border-bottom: 0;\n    }\n\n    .placeholder-row strong {\n      color: var(--green-2);\n    }\n\n    .blank {\n      min-height: 36px;\n      border: 1px dashed #b9c6bf;\n      border-radius: 7px;\n      background: #fafcfb;\n    }\n\n    .signature-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 14px;\n    }\n\n    label {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--green-2);\n      font-weight: 700;\n    }\n\n    input,\n    textarea {\n      width: 100%;\n      border: 1px solid #cbd8d1;\n      border-radius: 7px;\n      padding: 11px 12px;\n      font: inherit;\n      background: #fff;\n      color: var(--ink);\n    }\n\n    textarea {\n      min-height: 84px;\n      resize: vertical;\n    }\n\n    .field {\n      margin-bottom: 14px;\n    }\n\n    .signature-pad {\n      width: 100%;\n      height: 170px;\n      border: 1px dashed #9fb4aa;\n      border-radius: 8px;\n      background: #fff;\n      touch-action: none;\n    }\n\n    .checkbox-row {\n      display: flex;\n      align-items: flex-start;\n      gap: 9px;\n      margin: 12px 0 16px;\n      color: var(--muted);\n    }\n\n    .checkbox-row input {\n      width: auto;\n      margin-top: 5px;\n    }\n\n    .buttons {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 10px;\n    }\n\n    button {\n      border: 0;\n      border-radius: 7px;\n      padding: 11px 15px;\n      font: inherit;\n      font-weight: 700;\n      cursor: pointer;\n    }\n\n    .primary {\n      background: var(--green);\n      color: #fff;\n    }\n\n    .secondary {\n      background: #e4ece8;\n      color: var(--ink);\n    }\n\n    .notice {\n      display: none;\n      margin-top: 12px;\n      color: var(--green-2);\n      font-weight: 700;\n    }\n\n    .footer {\n      padding: 34px 0 46px;\n      color: var(--muted);\n      font-size: 14px;\n      text-align: center;\n    }\n\n    @media print {\n      body {\n        background: #fff;\n      }\n\n      .hero {\n        min-height: auto;\n        padding: 36px 24px;\n      }\n\n      .summary-strip {\n        margin-top: 0;\n      }\n\n      .summary-item,\n      .panel,\n      .scope-item,\n      .phase,\n      .risk {\n        box-shadow: none;\n      }\n    }\n\n    @media (max-width: 820px) {\n      .hero {\n        min-height: 66vh;\n        padding: 36px 18px 78px;\n      }\n\n      .hero-inner,\n      .wrap {\n        width: min(100% - 24px, 1080px);\n      }\n\n      h1 {\n        font-size: 40px;\n      }\n\n      .hero p {\n        font-size: 18px;\n      }\n\n      .summary-grid,\n      .grid-2,\n      .grid-3,\n      .scope-list,\n      .proposal-meta,\n      .signature-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .placeholder-row {\n        grid-template-columns: 1fr;\n      }\n    }\n  </style>\n</head>\n<body>\n  <header class=\"hero\">\n    <div class=\"hero-inner\">\n      <div class=\"eyebrow\">הצעת MVP | דרייב דוג</div>\n      <h1>מערכת CRM והזמנות ללקוחות חוזרים</h1>\n      <p>מסמך הצגת MVP למערכת שתאגד לקוחות, קטלוג מוצרים, מחירים אישיים, הזמנות, תשלומים, חשבוניות ומשלוחים במקום אחד.</p>\n      <div class=\"proposal-meta\">\n        <div class=\"meta-item\"><span>לכבוד</span><strong>דרייב דוג</strong></div>\n        <div class=\"meta-item\"><span>מגיש ההצעה</span><strong>Orma AI</strong></div>\n        <div class=\"meta-item\"><span>קישור</span><strong>proposals.orma-ai.com</strong></div>\n      </div>\n    </div>\n  </header>\n\n  <main>\n    <div class=\"summary-strip\">\n      <div class=\"wrap summary-grid\">\n        <div class=\"summary-item\">\n          <strong>~100</strong>\n          <span>לקוחות קיימים בתחילת הדרך</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>5-10</strong>\n          <span>הזמנות בתקופת פעילות טיפוסית</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>30-40</strong>\n          <span>מוצרים בקטלוג הראשוני</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>2 ימים</strong>\n          <span>התראה מינימלית לפני אספקה</span>\n        </div>\n      </div>\n    </div>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel accent\">\n          <span class=\"tag\">מטרת הפרויקט</span>\n          <h2>לעשות סדר בתהליך המכירה והאספקה</h2>\n          <p>המערכת נועדה להחליף עבודה מפוזרת בוואטסאפ ובטלפון במרכז ניהולי אחד, שבו בעל העסק רואה לקוחות, הזמנות, תשלומים, חשבוניות ומשלוחים בצורה מהירה וברורה.</p>\n        </article>\n        <article class=\"panel\">\n          <span class=\"tag\">קהל יעד</span>\n          <h2>לקוחות קיימים, לא חנות פתוחה לציבור</h2>\n          <p>הלקוח לא נרשם לבד. בעל העסק מכניס אותו למערכת, ולאחר מכן הלקוח יכול להיכנס עם מספר טלפון וקוד זמני כדי לבצע הזמנה חוזרת או לבחור מוצרים מהקטלוג.</p>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>01</span>\n          <h2>מה כלול ב-MVP</h2>\n          <p>גרסה ראשונה ממוקדת שמאפשרת שימוש אמיתי בעסק בלי לבנות מערכת כבדה מדי.</p>\n        </div>\n        <div class=\"scope-list\">\n          <div class=\"scope-item\"><strong>ניהול לקוחות</strong><span>שם, טלפון, כתובת, אזור, הערות, היסטוריית הזמנות ומחירים אישיים.</span></div>\n          <div class=\"scope-item\"><strong>קטלוג מוצרים</strong><span>מותג, סדרה, סוג, טעם, משקל, מחיר בסיס ותמונה.</span></div>\n          <div class=\"scope-item\"><strong>מחירים והנחות</strong><span>מחיר קבוע ללקוח, הנחות ומבצעים פשוטים.</span></div>\n          <div class=\"scope-item\"><strong>פורטל לקוח</strong><span>כניסה עם טלפון וקוד זמני, צפייה בקטלוג והזמנה עצמאית.</span></div>\n          <div class=\"scope-item\"><strong>הזמנה חוזרת</strong><span>אפשרות מהירה להזמין שוב את המוצר האחרון שנרכש.</span></div>\n          <div class=\"scope-item\"><strong>עגלה והזמנה</strong><span>תמיכה בכמה מוצרים באותה הזמנה, כתובת, הערות ומועד אספקה.</span></div>\n          <div class=\"scope-item\"><strong>הזמנה ידנית</strong><span>בעל העסק יכול לפתוח הזמנה עבור לקוחות מבוגרים או הזמנות טלפוניות.</span></div>\n          <div class=\"scope-item\"><strong>תשלומים וחשבוניות</strong><span>קישור תשלום דרך משולם/Grow, קליטת סטטוס תשלום וחשבונית אונליין.</span></div>\n          <div class=\"scope-item\"><strong>מזומן לשליח</strong><span>אפשרות חריגה לתשלום מזומן, עם סימון ידני של סטטוס תשלום.</span></div>\n          <div class=\"scope-item\"><strong>מסך משלוחים</strong><span>רשימת הזמנות לפי תאריך, אזור וסטטוס תשלום.</span></div>\n        </div>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>02</span>\n            <h2>זרימת לקוח</h2>\n          </div>\n          <ol>\n            <li>נכנס לעמוד ההזמנות.</li>\n            <li>מזין טלפון ומקבל קוד זמני.</li>\n            <li>רואה קטלוג ומוצר אחרון שנרכש.</li>\n            <li>בוחר מוצרים וכמויות.</li>\n            <li>מאשר כתובת ומוסיף הערות.</li>\n            <li>בוחר תשלום אונליין או מזומן לשליח.</li>\n            <li>הזמנה נכנסת למערכת לניהול בעל העסק.</li>\n          </ol>\n        </article>\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>03</span>\n            <h2>זרימת בעל העסק</h2>\n          </div>\n          <ol>\n            <li>מוסיף לקוחות ומוצרים.</li>\n            <li>מגדיר מחירים אישיים והנחות.</li>\n            <li>פותח הזמנה ידנית כשצריך.</li>\n            <li>יוצר קישור תשלום ושולח ללקוח.</li>\n            <li>רואה תשלומים וחשבוניות.</li>\n            <li>מנהל משלוחים לפי אזור ותאריך.</li>\n          </ol>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel accent\">\n          <div class=\"section-head\">\n            <span>04</span>\n            <h2>אינטגרציית משולם / Grow</h2>\n          </div>\n          <ul>\n            <li>יצירת קישור תשלום להזמנה.</li>\n            <li>העברת הלקוח לעמוד תשלום של Grow.</li>\n            <li>קליטת סטטוס תשלום דרך callback / webhook.</li>\n            <li>שמירת מספר חשבונית וקישור חשבונית כאשר Grow מחזירה אותם.</li>\n            <li>אין שמירת פרטי אשראי במערכת.</li>\n          </ul>\n        </article>\n        <article class=\"risk\">\n          <div class=\"section-head\">\n            <span>סיכון פתוח</span>\n            <h2>חשבונית על מזומן לשליח</h2>\n          </div>\n          <p>תשלום אונליין דרך Grow מתאים ל-MVP. לגבי תשלום מזומן לשליח, צריך אישור טכני מ-Grow האם ניתן להפיק חשבונית מס/קבלה דרך API עבור עסקה שלא שולמה אונליין.</p>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>05</span>\n          <h2>תהליך עבודה מוצע</h2>\n        </div>\n        <div class=\"timeline\">\n          <div class=\"phase\">\n            <div>\n              <h3>אפיון סופי ומפת מסכים</h3>\n              <p>סגירת זרימות, סטטוסים, מסכים והתנהגות מרכזית לפני פיתוח.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>עיצוב ופיתוח בסיס ניהולי</h3>\n              <p>לקוחות, מוצרים, מחירים, הזמנות ידניות ודשבורד ניהולי.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>פורטל לקוח</h3>\n              <p>כניסה עם קוד, קטלוג, עגלה, כתובת, הערות והזמנה חוזרת.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>חיבור משולם / Grow</h3>\n              <p>קישור תשלום, webhook, סטטוס תשלום וחשבונית אונליין.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>בדיקות ועלייה לשימוש</h3>\n              <p>בדיקות מובייל, תרחישי תשלום, הזמנות ידניות, משלוחים ותיקונים אחרונים.</p>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>06</span>\n            <h2>הנחות עבודה</h2>\n          </div>\n          <ul>\n            <li>בעל העסק מזין לקוחות למערכת.</li>\n            <li>הלקוחות לא נרשמים לבד.</li>\n            <li>התשלום הרצוי הוא בזמן ההזמנה.</li>\n            <li>מזומן לשליח הוא חריג, לא ברירת מחדל.</li>\n            <li>המערכת צריכה לעבוד טוב גם במובייל וגם במחשב.</li>\n            <li>משלוחים מנוהלים ידנית לפי תאריך ואזור.</li>\n            <li>תחזוקה חודשית לאחר העלייה לאוויר: 300 ₪ + מע״מ לחודש.</li>\n          </ul>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>07</span>\n          <h2>אישור וחתימה דיגיטלית</h2>\n          <p>לאישור ההצעה, ניתן למלא פרטים ולחתום בתיבה. בלחיצה על אישור נוצר קובץ אישור חתום ונפתח מייל מוכן לשליחה ל-Orma AI.</p>\n        </div>\n        <div class=\"panel\">\n          <div class=\"signature-grid\">\n            <div>\n              <div class=\"field\">\n                <label for=\"signName\">שם מלא</label>\n                <input id=\"signName\" autocomplete=\"name\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signPhone\">טלפון</label>\n                <input id=\"signPhone\" autocomplete=\"tel\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signEmail\">אימייל</label>\n                <input id=\"signEmail\" autocomplete=\"email\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signNotes\">הערות</label>\n                <textarea id=\"signNotes\"></textarea>\n              </div>\n            </div>\n            <div>\n              <label for=\"signaturePad\">חתימה</label>\n              <canvas id=\"signaturePad\" class=\"signature-pad\"></canvas>\n              <label class=\"checkbox-row\">\n                <input id=\"signApproval\" type=\"checkbox\">\n                <span>אני מאשר את ההצעה, תכולת ה-MVP, תנאי העבודה והעלות החודשית של 300 ₪ + מע״מ כמפורט במסמך זה.</span>\n              </label>\n              <div class=\"buttons\">\n                <button class=\"primary\" type=\"button\" id=\"downloadApproval\">אישור ושליחת חתימה</button>\n                <button class=\"secondary\" type=\"button\" id=\"clearSignature\">ניקוי חתימה</button>\n                <button class=\"secondary\" type=\"button\" id=\"printProposal\">הדפסה / PDF</button>\n              </div>\n              <div class=\"notice\" id=\"signatureNotice\">נוצר קובץ אישור חתום ונפתח מייל ל־Ami@hai.tech. יש לצרף את הקובץ למייל ולשלוח.</div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n  </main>\n\n  <footer class=\"footer\">\n    Orma AI | פתרונות AI, אוטומציה ומערכות ניהול | proposals.orma-ai.com\n  </footer>\n  <script>\n    const canvas = document.getElementById('signaturePad');\n    const ctx = canvas.getContext('2d');\n    let drawing = false;\n\n    function resizeCanvas() {\n      const rect = canvas.getBoundingClientRect();\n      const image = canvas.toDataURL();\n      canvas.width = Math.max(1, Math.floor(rect.width * window.devicePixelRatio));\n      canvas.height = Math.max(1, Math.floor(rect.height * window.devicePixelRatio));\n      ctx.setTransform(window.devicePixelRatio, 0, 0, window.devicePixelRatio, 0, 0);\n      ctx.lineWidth = 2.3;\n      ctx.lineCap = 'round';\n      ctx.strokeStyle = '#14211c';\n      if (image) {\n        const img = new Image();\n        img.onload = () => ctx.drawImage(img, 0, 0, rect.width, rect.height);\n        img.src = image;\n      }\n    }\n\n    function point(event) {\n      const rect = canvas.getBoundingClientRect();\n      const touch = event.touches ? event.touches[0] : event;\n      return {\n        x: touch.clientX - rect.left,\n        y: touch.clientY - rect.top\n      };\n    }\n\n    function start(event) {\n      drawing = true;\n      const p = point(event);\n      ctx.beginPath();\n      ctx.moveTo(p.x, p.y);\n      event.preventDefault();\n    }\n\n    function draw(event) {\n      if (!drawing) return;\n      const p = point(event);\n      ctx.lineTo(p.x, p.y);\n      ctx.stroke();\n      event.preventDefault();\n    }\n\n    function stop() {\n      drawing = false;\n    }\n\n    function fieldValue(id) {\n      return document.getElementById(id).value.trim();\n    }\n\n    function signatureIsBlank() {\n      const pixels = ctx.getImageData(0, 0, canvas.width, canvas.height).data;\n      for (let i = 3; i < pixels.length; i += 4) {\n        if (pixels[i] !== 0) return false;\n      }\n      return true;\n    }\n\n    function downloadSignedApproval() {\n      const approved = document.getElementById('signApproval').checked;\n      const name = fieldValue('signName');\n      if (!approved || !name || signatureIsBlank()) {\n        alert('צריך למלא שם, לסמן אישור ולחתום לפני שליחה.');\n        return;\n      }\n\n      const signature = canvas.toDataURL('image/png');\n      const date = new Date().toLocaleString('he-IL');\n      const html = `<!doctype html><html lang=\"he\" dir=\"rtl\"><meta charset=\"utf-8\"><title>אישור הצעת MVP - דרייב דוג</title><body style=\"font-family:Arial,sans-serif;line-height:1.6;padding:32px;max-width:760px;margin:auto\"><h1>אישור הצעת MVP - דרייב דוג</h1><p><strong>תאריך אישור:</strong> ${date}</p><p><strong>שם מלא:</strong> ${fieldValue('signName')}</p><p><strong>טלפון:</strong> ${fieldValue('signPhone')}</p><p><strong>אימייל:</strong> ${fieldValue('signEmail')}</p><p><strong>הערות:</strong><br>${fieldValue('signNotes').replaceAll('\\n', '<br>')}</p><p>אני מאשר את ההצעה, תכולת ה-MVP, תנאי העבודה והעלות החודשית של 300 ₪ + מע״מ כמפורט במסמך.</p><h2>חתימה</h2><img src=\"${signature}\" style=\"border:1px solid #ccc;max-width:420px;width:100%\"><footer style=\"margin-top:32px;color:#667\">Orma AI | proposals.orma-ai.com</footer></body></html>`;\n      const blob = new Blob([html], { type: 'text/html;charset=utf-8' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = 'drive-dog-mvp-signed-approval.html';\n      document.body.appendChild(link);\n      link.click();\n      link.remove();\n      URL.revokeObjectURL(url);\n      document.getElementById('signatureNotice').style.display = 'block';\n\n      const subject = encodeURIComponent('אישור הצעת MVP - דרייב דוג');\n      const body = encodeURIComponent([\n        'שלום,',\n        '',\n        'מצורף אישור חתום להצעת MVP - דרייב דוג.',\n        '',\n        `שם: ${fieldValue('signName')}`,\n        `טלפון: ${fieldValue('signPhone')}`,\n        `אימייל: ${fieldValue('signEmail')}`,\n        `תאריך אישור: ${date}`,\n        '',\n        'הערות:',\n        fieldValue('signNotes') || '-',\n        '',\n        'יש לצרף למייל את קובץ האישור החתום שירד למחשב/טלפון.'\n      ].join('\\n'));\n      window.location.href = `mailto:Ami@hai.tech?subject=${subject}&body=${body}`;\n    }\n\n    window.addEventListener('resize', resizeCanvas);\n    resizeCanvas();\n    canvas.addEventListener('mousedown', start);\n    canvas.addEventListener('mousemove', draw);\n    window.addEventListener('mouseup', stop);\n    canvas.addEventListener('touchstart', start, { passive: false });\n    canvas.addEventListener('touchmove', draw, { passive: false });\n    window.addEventListener('touchend', stop);\n    document.getElementById('clearSignature').addEventListener('click', () => {\n      ctx.clearRect(0, 0, canvas.width, canvas.height);\n    });\n    document.getElementById('printProposal').addEventListener('click', () => window.print());\n    document.getElementById('downloadApproval').addEventListener('click', downloadSignedApproval);\n  </script>\n</body>\n</html>\n";

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const html = url.pathname.startsWith("/proposal") ? proposalHtml : questionnaireHtml;

    return new Response(html, {
      headers: {
        "content-type": "text/html; charset=utf-8",
        "cache-control": "public, max-age=300"
      }
    });
  }
};
